package main

import (
	"fmt"
	"math"
)

func calculate(a float64, b float64, op string) float64 {
	switch op {
	case "+":
		return a + b
	case "-":
		return a - b
	case "*":
		return a * b
	case "/":
		if b == 0 {
			fmt.Println("Hata: Sifira bolme!")
			return math.NaN()
		}
		return a / b
	default:
		fmt.Println("Gecersiz islem:", op)
		return math.NaN()
	}
}

func main() {
	x, y := 15.0, 4.0

	fmt.Println("x =", x, ", y =", y)
	fmt.Println("x + y =", calculate(x, y, "+"))
	fmt.Println("x - y =", calculate(x, y, "-"))
	fmt.Println("x * y =", calculate(x, y, "*"))
	fmt.Println("x / y =", calculate(x, y, "/"))

	fmt.Println("\nSifira bolme testi:")
	calculate(10, 0, "/")

	// Yuzde hesaplama
	total, discount := 250.0, 15.0
	finalPrice := total - (total * discount / 100)
	fmt.Printf("\n%.0f TL'nin %%%.0f indirimli hali: %.1f TL\n", total, discount, finalPrice)
}
